<?php if (!defined('ABSPATH')) exit; ?>
<div class="bg-white rounded-xl shadow-md p-6 sticky top-6"><h3 class="text-xl font-bold mb-4">Filtros</h3><form method="get"><div class="mb-4"><label class="block text-sm font-semibold mb-2">Fecha desde</label><input type="date" name="fecha_desde" value="<?php echo isset($_GET['fecha_desde']) ? esc_attr($_GET['fecha_desde']) : ''; ?>" min="<?php echo date('Y-m-d'); ?>" class="w-full px-4 py-2 border rounded-lg"/></div><div class="mb-4"><label class="block text-sm font-semibold mb-2">Categoría</label><?php $cats = get_terms(array('taxonomy' => 'categoria_evento', 'hide_empty' => true)); if ($cats) : echo '<select name="categoria" class="w-full px-4 py-2 border rounded-lg"><option value="">Todas</option>'; foreach ($cats as $cat) echo '<option value="' . $cat->slug . '" ' . selected(isset($_GET['categoria']) ? $_GET['categoria'] : '', $cat->slug, false) . '>' . $cat->name . '</option>'; echo '</select>'; endif; ?></div><div class="mb-4"><label class="block text-sm font-semibold mb-2">Precio</label><select name="precio" class="w-full px-4 py-2 border rounded-lg"><option value="">Todos</option><option value="gratis" <?php selected(isset($_GET['precio']) ? $_GET['precio'] : '', 'gratis'); ?>>Gratis</option><option value="pago" <?php selected(isset($_GET['precio']) ? $_GET['precio'] : '', 'pago'); ?>>De pago</option></select></div><button type="submit" class="w-full px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-dark">Filtrar</button><?php if (!empty($_GET['fecha_desde']) || !empty($_GET['categoria']) || !empty($_GET['precio'])) : ?><a href="<?php echo get_post_type_archive_link('evento'); ?>" class="block text-center mt-3 px-4 py-2 bg-gray-100 rounded-lg">Limpiar</a><?php endif; ?></form></div>
